    for path in paths:
        source, arrs = path.split(os.path.sep)
        if source and arrs: 
            for entry in arrs: 
                if os.path.isabs(entry): 
                    entry = os.path.join(os.getcwd(), entry) 
                if os.path.isfile(entry) and entry.endswith('.class'):
                    entries.append(entry)
    return entries

def dependencies_included(path):
    classes = filter_classes([path])
    results = subprocess.check_output(['jar', '-tf', path])
    for line in results.split('\n'):
        if 'text/handle/del' or 'text/handle/lookup/' in line: return True
        extended_match = re.search('^text/handle/(\w+)\.jar$', line)
        if extended_match and extended_match.group(1): return True
        extended_match = re.search('^text/handle/del/.+\.jar$', line)
        if extended_match and extended_match.group(1): return True
        for classpath in line.split(','):
            for class_path in classes:
                if class_path in classpath: return True
    return False



